78	export interface Damage {
79	  itemType: string;
80	  amount: number;
81	}
82	
83	export interface Incident {
84	  cause: string;
85	  damages: Damage[];
86	}
87	
88	export interface ClaimResult {
89	  payout: number;
90	  remainingCap: number;
91	}
92	
93	const DEDUCTIBLE = 100;
94	const HIGH_ENCHANT_DAMAGE_THRESHOLD = 8;
95	const HIGH_ENCHANT_DAMAGE_DIVISOR = 2;
96	
97	// Reimbursable amount for a single damage entry, before the per-event deductible.
98	// High-enchantment items (enchantment >= 8) are reimbursed at 50% of damage.
99	function reimbursableAmount(policy: Policy, damage: Damage): number {
100	  const damagedItem = policy.items.find((item) => item.type === damage.itemType);
101	  const isHighEnchant = (damagedItem?.enchantment ?? 0) >= HIGH_ENCHANT_DAMAGE_THRESHOLD;
102	  return isHighEnchant ? damage.amount / HIGH_ENCHANT_DAMAGE_DIVISOR : damage.amount;
103	}
104	
105	export function claim(policy: Policy, incident: Incident, remainingCap: number): ClaimResult {
106	  const rawPayout = incident.damages.reduce(
107	    (sum, damage) => sum + reimbursableAmount(policy, damage) - DEDUCTIBLE,
108	    0,
109	  );
110	  const cappedPayout = Math.min(rawPayout, remainingCap);
111	  // Round DOWN in MHPCO's favor (payouts) — mirrors Math.ceil on premiums.
112	  const payout = Math.floor(cappedPayout);
113	  return { payout, remainingCap: remainingCap - payout };
114	}
115	
116	export function quote(customer: Customer, items: Item[], options?: QuoteOptions): number {
117	  const baseTotal = policyBaseTotal(items);
118	  const surchargeTotal = items.reduce((sum, item) => sum + itemSurcharges(item), 0);
119	  const firstInsurance = baseTotal * FIRST_INSURANCE_RATE;
120	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT : 0;
121	  const followUpDiscount = options?.isFollowUp ? FOLLOW_UP_DISCOUNT : 0;
122	  const premium =
123	    baseTotal + surchargeTotal + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE;
124	  return Math.ceil(premium);
125	}
